const et = $now.setZone('America/New_York');
const dateStr = et.toFormat('yyyy-MM-dd');
const HOLIDAYS_2026 = ['2026-01-01','2026-01-19','2026-02-16','2026-04-03','2026-05-25','2026-06-19','2026-07-03','2026-09-07','2026-11-26','2026-12-25'];
if (et.weekday > 5) { console.log('QTP_DRT skip: weekend ' + dateStr); return []; }
if (HOLIDAYS_2026.includes(dateStr)) { console.log('QTP_DRT skip: NYSE holiday ' + dateStr); return []; }
const row = $input.first().json;
let symbols = row.top_symbols;
if (typeof symbols === 'string') { try { symbols = JSON.parse(symbols); } catch (e) { symbols = []; } }
if (!Array.isArray(symbols)) symbols = [];
let sides = row.yesterday_sides;
if (typeof sides === 'string') { try { sides = JSON.parse(sides); } catch (e) { sides = {}; } }
if (!sides || typeof sides !== 'object' || Array.isArray(sides)) sides = {};
const degradations = [];
if (symbols.length === 0) degradations.push('watchlist_empty_no_exec_flow_audit_rows_last_5d');
if (Object.keys(sides).length === 0) degradations.push('no_yesterday_signal_counts');
const symList = symbols.length ? symbols.join(', ') : '(none available)';
const sidesTxt = Object.keys(sides).length ? Object.keys(sides).map(function (k) { return k + '=' + sides[k]; }).join(', ') : '(none)';
const ctx = 'Trading date: ' + dateStr + ' (pre-market, approx 08:30 ET).\n' +
  'Active QTP watchlist (top symbols by 5-day pipeline signal frequency): ' + symList + '.\n' +
  'Yesterday pipeline signal counts by side: ' + sidesTxt + '.\n';
const bullPrompt = ctx + '\nYou are the BULL analyst on a quant trading desk. Make the strongest evidence-based case FOR long exposure today: (1) market regime read, (2) sector-level opportunities, (3) a per-name bull case for EACH watchlist symbol above. Be concrete about what evidence would support each claim (macro backdrop, trend structure, breadth, positioning, catalysts). Acknowledge nothing about the bear side; that is another analyst. Maximum 600 words, plain prose only - no JSON, no curly braces, no markdown headers.';
const bearPrompt = ctx + '\nYou are the BEAR analyst on a quant trading desk. Make the strongest evidence-based case AGAINST long exposure today and FOR the short side: (1) market regime risks, (2) sector-level vulnerabilities, (3) a per-name bear case for EACH watchlist symbol above. Be concrete about what evidence would support each claim (macro risks, distribution patterns, crowding, downside catalysts). Acknowledge nothing about the bull side; that is another analyst. Maximum 600 words, plain prose only - no JSON, no curly braces, no markdown headers.';
const judgeSystem = 'You are the JUDGE on a quant trading desk. You will receive a BULL brief and a BEAR brief for the same trading day and watchlist. Weigh both and issue a verdict. Output STRICT JSON only - a single JSON object, no markdown fences, no commentary, no trailing text. Required top-level keys: market_regime (string, e.g. RISK_ON, RISK_OFF, CHOP, TRENDING_UP, TRENDING_DOWN); regime_confidence (number between 0 and 1); regime_rationale (string); spy_view (string, one-paragraph directional view on SPY for today); sector_tilts (array of objects, each with keys: sector as string, tilt as one of overweight or neutral or underweight, note as string); names (array of objects, each with keys: symbol as string, stance as one of long or short or avoid, confidence as number between 0 and 1, bull_case as string, bear_case as string, judge_note as string). The names array MUST contain exactly one entry for EVERY provided symbol.';
return [{ json: { trading_date: dateStr, symbols: symbols, yesterday_sides: sides, degradations: degradations, bull_prompt: bullPrompt, bear_prompt: bearPrompt, judge_system: judgeSystem } }];

const base = $('Build Crew Prompts').first().json;
const bullOut = $('Bull Analyst').first().json;
const bearOut = $('Bear Analyst').first().json;
const bullText = bullOut && typeof bullOut.text === 'string' && bullOut.text.trim() ? bullOut.text.trim() : null;
const bearText = bearOut && typeof bearOut.text === 'string' && bearOut.text.trim() ? bearOut.text.trim() : null;
if (!bullText) { throw new Error('QTP_DRT FAIL LOUD: Bull analyst returned no text. Raw output head: ' + JSON.stringify(bullOut).slice(0, 500)); }
if (!bearText) { throw new Error('QTP_DRT FAIL LOUD: Bear analyst returned no text. Raw output head: ' + JSON.stringify(bearOut).slice(0, 500)); }
const sides = base.yesterday_sides || {};
const sidesTxt = Object.keys(sides).length ? Object.keys(sides).map(function (k) { return k + '=' + sides[k]; }).join(', ') : '(none)';
const judgeUser = 'Trading date: ' + base.trading_date + '\nSymbols to judge (one names entry each): ' + (base.symbols.length ? base.symbols.join(', ') : '(none - return empty names array)') + '\nYesterday pipeline signal counts by side: ' + sidesTxt + '\n\n=== BULL ANALYST BRIEF ===\n' + bullText + '\n\n=== BEAR ANALYST BRIEF ===\n' + bearText + '\n\nWeigh both briefs and output the strict JSON verdict now.';
return [{ json: { judge_user: judgeUser, bull_text: bullText, bear_text: bearText } }];

const judgeOut = $input.first().json;
const meta = $('Build Crew Prompts').first().json;
const crew = $('Assemble Judge Request').first().json;
const rawJudge = judgeOut && typeof judgeOut.text === 'string' && judgeOut.text.trim() ? judgeOut.text.trim() : null;
if (!rawJudge) { throw new Error('QTP_DRT FAIL LOUD: Judge returned no text. Raw output head: ' + JSON.stringify(judgeOut).slice(0, 500)); }
let jsonText = String(rawJudge).trim();
const FENCE = String.fromCharCode(96, 96, 96);
if (jsonText.indexOf(FENCE) !== -1) {
  const firstFence = jsonText.indexOf(FENCE);
  let start = jsonText.indexOf('\n', firstFence);
  if (start === -1) start = firstFence + 3; else start = start + 1;
  const end = jsonText.lastIndexOf(FENCE);
  if (end > start) jsonText = jsonText.slice(start, end);
  jsonText = jsonText.trim();
}
let verdict;
try { verdict = JSON.parse(jsonText); } catch (e) {
  throw new Error('QTP_DRT FAIL LOUD: Judge output is not valid strict JSON after fence-stripping. Parse error: ' + e.message + '. Output head: ' + jsonText.slice(0, 400));
}
const missing = [];
if (typeof verdict.market_regime !== 'string' || !verdict.market_regime) missing.push('market_regime');
if (typeof verdict.regime_rationale !== 'string') missing.push('regime_rationale');
if (typeof verdict.spy_view !== 'string') missing.push('spy_view');
if (!Array.isArray(verdict.sector_tilts)) missing.push('sector_tilts');
if (!Array.isArray(verdict.names)) missing.push('names');
if (missing.length) { throw new Error('QTP_DRT FAIL LOUD: Judge JSON missing/invalid required fields: ' + missing.join(', ') + '. Output head: ' + jsonText.slice(0, 400)); }
const degradations = (meta.degradations || []).slice();
degradations.push('vix_level_not_sourced_in_v1');
function sanDollar(s) { return String(s).replace(/\$(?=\d)/g, 'USD '); }
function sqlText(v) { return "'" + sanDollar(v == null ? '' : v).replace(/'/g, "''") + "'"; }
function deepSan(o) { if (typeof o === 'string') return sanDollar(o); if (Array.isArray(o)) return o.map(deepSan); if (o && typeof o === 'object') { const r = {}; for (const k of Object.keys(o)) { r[k] = deepSan(o[k]); } return r; } return o; }
function jsonbLit(o) { return "'" + JSON.stringify(deepSan(o)).replace(/'/g, "''") + "'::jsonb"; }
let rc = Number(verdict.regime_confidence);
let rcSql;
if (Number.isFinite(rc)) { rcSql = String(Math.max(0, Math.min(1, rc))); } else { rcSql = 'NULL'; degradations.push('regime_confidence_not_numeric'); }
const et = $now.setZone('America/New_York');
const thesisId = 'drt_' + et.toFormat('yyyyMMdd_HHmm');
const ttlSql = "('" + meta.trading_date + " 16:30:00'::timestamp AT TIME ZONE 'America/New_York')";
const rawPayload = { bull: crew.bull_text, bear: crew.bear_text, judge_raw: rawJudge };
const notes = 'QTP_DRT v1: ' + (degradations.length ? 'degradations: ' + degradations.join('; ') : 'clean run');
const insertSql = 'INSERT INTO quantum.daily_research_thesis (thesis_id, thesis_date, market_regime, regime_confidence, regime_rationale, vix_level, spy_view, sector_tilts, names, bull_model, bear_model, judge_model, crew_version, ttl_expires_at, raw_payload, notes) VALUES (' +
  sqlText(thesisId) + ', ' +
  "'" + meta.trading_date + "'::date, " +
  sqlText(verdict.market_regime) + ', ' +
  rcSql + ', ' +
  sqlText(verdict.regime_rationale) + ', ' +
  'NULL, ' +
  sqlText(verdict.spy_view) + ', ' +
  jsonbLit(verdict.sector_tilts) + ', ' +
  jsonbLit(verdict.names) + ', ' +
  "'grok-3-mini', 'grok-3-mini', 'grok-3', " +
  "'QTP_DRT_CREW_v1.0_20260706', " +
  ttlSql + ', ' +
  jsonbLit(rawPayload) + ', ' +
  sqlText(notes) +
  ') RETURNING thesis_id, thesis_date, market_regime, regime_confidence;';
if (/\$\d/.test(insertSql)) { throw new Error('QTP_DRT FAIL LOUD: insert_sql still contains a $<digit> sequence after sanitization - refusing to send (pg-param bug guard).'); }
return [{ json: { insert_sql: insertSql, thesis_id: thesisId } }];
